    result, err := parseCautResponse([]byte(jsonData))
    if err != nil {
        t.Fatalf("Parse failed: %v", err)
    }

    if result.SchemaVersion != "caut.v1" {
        t.Errorf("SchemaVersion = %q, want caut.v1", result.SchemaVersion)
    }
    if len(result.Payloads) != 1 {
        t.Fatalf("Expected 1 payload, got %d", len(result.Payloads))
    }
    if result.Payloads[0].Provider != "claude" {
        t.Errorf("Provider = %q, want claude", result.Payloads[0].Provider)
    }
}

func TestParseResponse_InvalidJSON(t *testing.T) {
    _, err := parseCautResponse([]byte("invalid json"))
    if err == nil {
        t.Error("Expected error for invalid JSON")
    }
}

func TestClient_FetchUsage_Timeout(t *testing.T) {
    c := &Client{
